```

### Module 46 - DriftMonitor JSON Operations
```javascript
// File: /app/project/src/module_46.js
// Lines: 206-212 - Kafka message parsing
.on('data', (msg) => {
    try {
        const payload = JSON.parse(msg.value.toString());
        this._message$.next(payload);
    } catch (err) {
        log.warn(`Failed to parse message: ${err.message}`);
    }
})

// Lines: 296-299 - Event emission with JSON.stringify
_emitRetrainEvent(payload) {
    const event = {
        event_type: 'model.retrain.requested',
        timestamp: Date.now(),
        metadata: {
            reason: 'concept_drift',
            ...payload,
        },
    };
    const buf = Buffer.from(JSON.stringify(event));
```

### Module 50 - MetricMonitor JSON Operations
```javascript
// File: /app/project/src/module_50.js
// Lines: 82-99 - Config parsing at startup
let MONITORED_METRICS;
try {
    MONITORED_METRICS = JSON.parse(METRICS_CONFIG_JSON);
} catch (err) {
    console.error('Invalid METRICS_CONFIG_JSON; falling back to defaults.', err);
    MONITORED_METRICS = {
