}

// Lines: 205-214 - Kafka message production with JSON.stringify
send$(topic, payload) {
    return this.connected$.pipe(
        switchMap(() =>
            from(
                this.producer.send({
                    topic,
                    messages: [
                        {
                            key: payload.metricName,
                            value: JSON.stringify(payload),
                            timestamp: Date.now().toString()
                        }
                    ]
                })
            )
        ),
        map(() => void 0)
