     2→// File: src/module_14.js
     3→// Project: AgoraPulse - Real-Time Social Signal Intelligence
     4→//
     5→// -----------------------------------------------------------------------------
     6→// WindowedSentimentAggregator
     7→// -----------------------------------------------------------------------------
     8→// Listens to low-level “sentiment-prediction” events coming from the real-time
     9→// feature pipeline, performs sliding-window aggregation per community, and
    10→// republishes window-level aggregates to a downstream Kafka topic so that
    11→// dashboards, alerting rules, and adaptive-content engines can react in near
    12→// real time.
    13→//
    14→// ─── Tech Stack ────────────────────────────────────────────────────────────────
    15→// • KafkaJS             – stream transport (consumer / producer)
    16→// • RxJS                – reactive in-process pipeline
    17→// • Axios               – HTTP client for model-monitoring callbacks
    18→// • uuid                – correlation / id generation
    19→// -----------------------------------------------------------------------------
    20→// Author: AgoraPulse Core Engineering
    21→// License: Apache-2.0
    22→// -----------------------------------------------------------------------------
    23→
    24→/* eslint-disable no-console */
    25→
    26→'use strict';
    27→
    28→const { Kafka, logLevel } = require('kafkajs');
    29→const {
    30→  Subject,
    31→  BehaviorSubject,
    32→  timer,
    33→  of,
    34→} = require('rxjs');
    35→const {
    36→  groupBy,
    37→  bufferTime,
    38→  mergeMap,
    39→  map,
    40→  filter,
    41→  tap,
    42→  catchError,
    43→  retryWhen,
    44→  delayWhen,
    45→} = require('rxjs/operators');
    46→const axios = require('axios').default;
    47→const { v4: uuidv4 } = require('uuid');
    48→
    49→/* -------------------------------------------------------------------------- */
    50→/*                               Config Defaults                              */
    51→/* -------------------------------------------------------------------------- */
    52→
    53→/**
    54→ * Default configuration.  Override by passing a partial config object when
    55→ * instantiating the aggregator or by using environment variables.
    56→ */
    57→const DEFAULT_CONFIG = Object.freeze({
    58→  kafka: {
    59→    brokers: process.env.KAFKA_BROKERS?.split(',') || ['localhost:9092'],
    60→    clientId: process.env.KAFKA_CLIENT_ID || 'agorapulse-sentiment-aggregator',
    61→    ssl: process.env.KAFKA_SSL === 'true',
    62→  },
    63→  topics: {
    64→    source: process.env.KAFKA_TOPIC_SOURCE || 'social.predictions.sentiment',
    65→    sink: process.env.KAFKA_TOPIC_SINK || 'social.aggregates.sentiment.window',
    66→  },
    67→  window: {
    68→    /* Sliding time window size in milliseconds */
    69→    durationMs: Number(process.env.AGG_WINDOW_MS) || 30_000,
    70→    /* Maximum number of items kept inside a single buffer before it flushes */
    71→    maxBufferSize: Number(process.env.AGG_WINDOW_MAX_SIZE) || 5_000,
    72→  },
    73→  monitoring: {
    74→    /* HTTP Endpoint to push anomaly notifications to model-monitoring service */
    75→    endpoint:
    76→      process.env.MODEL_MON_MONITORING_ENDPOINT ||
    77→      'http://localhost:7000/api/v1/alerts',
    78→    /* If `avgSentiment` goes below this threshold an alert is emitted */
    79→    negativeSentimentThreshold:
    80→      Number(process.env.NEG_SENTIMENT_THRESHOLD) || -0.6,
    81→  },
    82→  retry: {
    83→    /* Exponential back-off base (ms) for transient failures */
    84→    baseDelayMs: 1000,
    85→    /* Maximum amount of retries before giving up */
    86→    maxRetries: 5,
    87→  },
    88→});
    89→
    90→/* -------------------------------------------------------------------------- */
    91→/*                             Utility / Type Guards                          */
    92→/* -------------------------------------------------------------------------- */
    93→
    94→/**
    95→ * Parses a Kafka message value (assumed JSON) into a plain object.
    96→ * @param {import('kafkajs').KafkaMessage} msg
    97→ * @returns {{communityId: string, sentiment: number, timestamp: number, ...}}
    98→ */
    99→function parseMessage(msg) {
   100→  try {
   101→    // KafkaJS delivers the message value as a Buffer
   102→    return JSON.parse(msg.value.toString('utf8'));
   103→  } catch (err) {
   104→    console.error(`[Aggregator] Failed to parse message:`, err);
   105→    return null;
   106→  }
   107→}
   108→
   109→/**
   110→ * Calculates windowed sentiment statistics.
   111→ * @param {Array<{sentiment: number, timestamp: number}>} events
   112→ * @returns {{count: number, avgSentiment: number, min: number, max: number}}
   113→ */
   114→function calculateStats(events) {
   115→  const count = events.length;
   116→  if (count === 0) {
   117→    return { count: 0, avgSentiment: 0, min: 0, max: 0 };
   118→  }
   119→  let sum = 0;
   120→  let min = Infinity;
   121→  let max = -Infinity;
   122→  for (const { sentiment } of events) {
   123→    sum += sentiment;
   124→    if (sentiment < min) min = sentiment;
   125→    if (sentiment > max) max = sentiment;
   126→  }
   127→  return {
   128→    count,
   129→    avgSentiment: sum / count,
   130→    min,
   131→    max,
   132→  };
   133→}
   134→
   135→/* -------------------------------------------------------------------------- */
   136→/*                          WindowedSentimentAggregator                       */
   137→/* -------------------------------------------------------------------------- */
   138→
   139→class WindowedSentimentAggregator {
   140→  /**
   141→   * @param {Partial<typeof DEFAULT_CONFIG>} [customConfig]
   142→   */
   143→  constructor(customConfig = {}) {
   144→    this.config = deepMerge(DEFAULT_CONFIG, customConfig);
   145→
   146→    // Kafka client / producer / consumer
   147→    this.kafka = new Kafka({
   148→      clientId: this.config.kafka.clientId,
   149→      brokers: this.config.kafka.brokers,
   150→      ssl: this.config.kafka.ssl,
   151→      logLevel: logLevel.NOTHING,
   152→    });
   153→
   154→    this.producer = this.kafka.producer();
   155→    this.consumer = this.kafka.consumer({ groupId: this.config.kafka.clientId });
   156→
   157→    // RxJS subject as the bridge between Kafka messages and reactive ops
   158→    this._event$ = new Subject();
   159→
   160→    // Stop / shutdown coordination
   161→    this._isShuttingDown$ = new BehaviorSubject(false);
   162→  }
   163→
   164→  /* -------------------------------------------------------------------- */
   165→  /*                              Lifecycle                               */
   166→  /* -------------------------------------------------------------------- */
   167→
   168→  /**
   169→   * Initializes Kafka connections and spins up the reactive pipeline.
   170→   */
   171→  async start() {
   172→    console.info('[Aggregator] Starting WindowedSentimentAggregator …');
   173→
   174→    await Promise.all([this.producer.connect(), this.consumer.connect()]);
   175→
   176→    await this.consumer.subscribe({
   177→      topic: this.config.topics.source,
   178→      fromBeginning: false,
   179→    });
   180→
   181→    // Forward valid messages to the Subject
   182→    this.consumer.run({
   183→      eachMessage: async ({ message }) => {
   184→        const payload = parseMessage(message);
   185→        if (payload && payload.communityId && typeof payload.sentiment === 'number') {
   186→          this._event$.next(payload);
   187→        }
   188→        // Invalid messages are silently ignored; statistics would capture them separately
   189→      },
   190→    });
   191→
   192→    // Build reactive graph
   193→    this._subscription = this._buildReactivePipeline();
   194→
   195→    // Graceful shutdown signals
   196→    process.once('SIGINT', () => this.stop());
   197→    process.once('SIGTERM', () => this.stop());
   198→  }
   199→
   200→  /**
   201→   * Tears down Kafka resources and reactive streams.
