───────────────────────────────────────────────────────────────────── */\n\n/**\n * Real-time drift monitor using RxJS & Kafka.\n */\nclass DriftMonitor {\n    /**\n     * @param {Object} params\n     * @param {Object} params.kafkaConfig      – Global Kafka client config\n     * @param {Object} params.consumerConfig   – Consumer-specific config\n     * @param {string} params.sourceTopic      – Topic with model inferences\n     * @param {string} params.targetTopic      – Topic for retrain events\n     * @param {number} params.windowMs         – Sliding window size (ms)\n     * @param {number} params.baselineMs       – Time to learn baseline (ms)\n     * @param {number} params.thresholdInitial – Starting KL divergence threshold\n     * @param {number} params.thresholdGrowth  – Factor to grow threshold over time\n     */\n    constructor({\n        kafkaConfig,\n        consumerConfig,\n        sourceTopic,\n        targetTopic = 'model.retrain',\n        windowMs = 30_000,\n        baselineMs = 600_000,\n        thresholdInitial = 0.05,\n        thresholdGrowth = 1.5,\n    }) {\n        if (!sourceTopic) throw new Error('sourceTopic is required');\n\n        this.kafkaConfig = kafkaConfig;\n        this.consumerConfig = consumerConfig;\n        this.sourceTopic = sourceTopic;\n        this.targetTopic = targetTopic;\n        this.windowMs = windowMs;\n        this.baselineMs = baselineMs;\n        this.threshold = thresholdInitial;\n        this.thresholdGrowth = thresholdGrowth;\n\n        this._message$ = new Subject(); // central message bus\n        this._baselineReady = false;\n        this._baselineDistribution = null;\n\n        this._consumer = null;\n        this._producer = null;\n        this._subscriptions = [];\n    }\n\n    /* ─────────────── Public API ─────────────── */\n\n    /**\n     * Initialize Kafka clients and reactive pipeline.\n     */\n    async start() {\n        await this._initKafka();\n        this._wireStreamPipeline();\n        log.info('DriftMonitor started.');\n    }\n\n    /**\n     * Gracefully flush and close all resources.\n     */\n    async stop() {\n        log.info('Stopping DriftMonitor …');\n        this._subscriptions.forEach((sub) => sub.unsubscribe());\n\n        await Promise.all([\n            new Promise((res) => this._consumer.disconnect(res)),\n            new Promise((res) => this._producer.flush(10_000, () => this._producer.disconnect(res))),\n        ]);\n\n        log.info('DriftMonitor stopped.');\n    }\n\n    /* ─────────────── Internal – Kafka setup ─────────────── */\n\n    async _initKafka() {\n        this._consumer = new Kafka.KafkaConsumer(\n            this.kafkaConfig,\n            Object.assign(\n                {\n                    'group.id': `drift-monitor-${Date.now()}`,\n                    'enable.auto.commit': true,\n                },\n                this.consumerConfig,\n            ),\n        );\n\n        this._producer = new Kafka.Producer(this.kafkaConfig);\n\n        // Consumer wiring\n        await new Promise((resolve, reject) => {\n            this._consumer\n                .on('ready', () => {\n                    this._consumer.subscribe([this.sourceTopic]);\n                    this._consumer.consume();\n                    resolve();\n                })\n                .on('data', (msg) => {\n                    try {\n                        const payload = JSON.parse(msg.value.toString());\n                        this._message$.next(payload);\n                    } catch (err) {\n                        log.warn(`Failed to parse message: ${err.message}`);\n                    }\n                })\n                .on('event.error', reject);\n\n            this._consumer.connect();\n        });\n\n        // Producer wiring\n        await new Promise((resolve, reject) => {\n            this._producer\n                .on('ready', resolve)\n                .on('event.error', reject)\n                .connect();\n        });\n\n        log.info('Kafka consumer & producer ready.');\n    }\n\n    /* ─────────────── Internal – Stream pipeline ─────────────── */\n\n    _wireStreamPipeline() {\n        // Window the messages into bufferTime windows\n        const window$ = this._message$.pipe(bufferTime(this.windowMs), filter((w) => w.length > 0));\n\n        // Baseline learner: first N minutes form baseline distribution\n        const baseline$ = window$.pipe(\n            takeUntil(timer(this.baselineMs)),\n            tap((w) => {\n                const dist = computeDistribution(w);\n                if (!this._baselineDistribution) {\n                    this._baselineDistribution = dist;\n                } else {\n                    // Exponential moving average to smooth baseline\n                    Object.keys(dist).forEach((k) => {\n                        this._baselineDistribution[k] =\n                            0.9 * this._baselineDistribution[k] + 0.1 * dist[k];\n                    });\n                }\n            }),\n        );\n\n        // After baseline period, start monitoring\n        const monitoring$ = window$.pipe(\n            skipUntil(timer(this.baselineMs)),\n            map((w) => ({\n                window: w,\n                distribution: computeDistribution(w),\n            })),\n            pairwise(),\n            map(([prev, curr]) => {\n                const kl = klDivergence(this._baselineDistribution, curr.distribution);\n                return { ...curr, kl };\n            }),\n            tap(({ kl }) => driftGauge.set(kl)),\n            filter(({ kl }) => kl >= this.threshold),\n            tap(({ kl }) => {\n                log.warn(`Drift detected: KL=${kl.toFixed(4)} exceeds threshold=${this.threshold}`);\n                this._emitRetrainEvent({ kl });\n                retrainCounter.inc();\n                // After each trigger, relax threshold to avoid flapping.\n                this.threshold *= this.thresholdGrowth;\n                log.info(`New drift threshold set to ${this.threshold.toFixed(4)}`);\n            }),\n            catchError((err, caught) => {\n                log.error(`Stream error: ${err.stack || err}`);\n                return caught; // restart stream\n            }),\n        );\n\n        // Subscriptions\n        this._subscriptions.push(baseline$.subscribe());\n        this._subscriptions.push(monitoring$.subscribe());\n    }\n\n    /* ─────────────── Internal – Retrain producer ─────────────── */\n\n    _emitRetrainEvent(payload) {\n        const event = {\n            event_type: 'model.retrain.requested',\n            timestamp: Date.now(),\n            metadata: {\n                reason: 'concept_drift',\n                ...payload,\n            },\n        };\n\n        const buf = Buffer.from(JSON.stringify(event));\n        this._producer.produce(\n            this.targetTopic,\n            null,\n            buf,\n            null,\n            Date.now(),\n            (err) => {\n                if (err) {\n                    log.error(`Failed to emit retrain event: ${err.message}`);\n                } else {\n                    log.info(`Retrain event produced to ${this.targetTopic}`);\n                }\n            },\n        );\n    }\n\n    /* ─────────────── Prometheus exposition ─────────────── */\n\n    /**\n     * Expose current metrics in Prometheus plain-text format.\n     * @returns {string}\n     */\n    getMetrics() {\n        return registry.metrics();\n    }\n}\n\n/* ──────────────────────────────────────────────────────────────────────────────\n * Factory helper\n * ─────────────────────────────────────────────────────────────────────────── */\n\n/**\n * Factory to instantiate a DriftMonitor from environment variables.\n */\nfunction createDriftMonitorFromEnv() {\n    const kafkaConfig = {\n        'metadata.broker.list': process.env.KAFKA_BROKERS || 'localhost:9092',\n        dr_cb: true,\n    };\n\n    return new DriftMonitor({\n        kafkaConfig,\n        consumerConfig: {},\n        sourceTopic: process.env.SOURCE_TOPIC || 'model.inference',\n        targetTopic: process.env.TARGET_TOPIC || 'model.retrain',\n        windowMs: parseInt(process.env.WINDOW_MS || '30000', 10),\n        baselineMs: parseInt(process.env.BASELINE_MS || '600000', 10),\n        thresholdInitial: parseFloat(process.env.KL_THRESHOLD || '0.05'),\n        thresholdGrowth: parseFloat(process.env.THRESHOLD_GROWTH || '1.5'),\n    });\n}\n\n/* ──────────────────────────────────────────────────────────────────────────────\n * Module exports\n * ─────────────────────────────────────────────────────────────────────────── */\nmodule.exports = {\n    DriftMonitor,\n    createDriftMonitorFromEnv,\n};\n```", "numLines": 358, "startLine": 1, "totalLines": 358}}

1→/**
     2→ * src/module_50.js
     3→ *
     4→ * AgoraPulse – Real-Time Social Signal Intelligence
     5→ *
     6→ * Module #50: Metric Monitor & Anomaly Publisher
     7→ * ==============================================
     8→ * Continuously queries Prometheus for model-serving/monitoring metrics,
     9→ * detects anomalies (breaches of configured thresholds or statistical change
    10→ * points), and publishes anomaly events to Kafka so that downstream pipelines
    11→ * (re-training triggers, alerting, dashboards) can react in near-real time.
    12→ *
    13→ * High-level flow:
    14→ *  ┌──────────────┐     poll()      ┌─────────────────┐
    15→ *  │ Prometheus   │ ───────────────▶│ MetricMonitor   │
    16→ *  └──────────────┘                 │  • thresholds   │
    17→ *                                   │  • change-point │
    18→ *                                   │  • debounce     │
    19→ *                                   └──────┬──────────┘
    20→ *                                          │ emit
    21→ *                                          ▼
    22→ *                                  ┌──────────────────┐
    23→ *                                  │ Kafka producer   │
    24→ *                                  └──────────────────┘
    25→ *
    26→ * The monitor is heavily RxJS-based and respects back-pressure.  When the
    27→ * Prometheus endpoint is slow or unreachable, we apply exponential back-off
    28→ * and circuit-breaking semantics to avoid cascading failures.
    29→ *
    30→ * NOTE:
    31→ *  - This file is intentionally written in plain JS (ES2020) to support both
    32→ *    Node.js ≥14 and older Lambda runtimes.  For TypeScript consumers, the
    33→ *    corresponding typings are generated in the `types/` folder.
    34→ */
    35→
    36→'use strict';
    37→
    38→//////////////////////////////
    39→// External Dependencies
    40→//////////////////////////////
    41→const { Kafka, logLevel } = require('kafkajs');
    42→const axios = require('axios').default;
    43→const Ajv = require('ajv').default;
    44→const addFormats = require('ajv-formats');
    45→const {
    46→    timer,
    47→    from,
    48→    EMPTY,
    49→    throwError,
    50→    defer,
    51→    Subject
    52→} = require('rxjs');
    53→const {
    54→    switchMap,
    55→    map,
    56→    catchError,
    57→    retryWhen,
    58→    filter,
    59→    tap,
    60→    takeUntil,
    61→    shareReplay,
    62→    delay,
    63→    scan,
    64→    throttleTime
    65→} = require('rxjs/operators');
    66→
    67→//////////////////////////////
    68→// Environment & Config
    69→//////////////////////////////
    70→
    71→const {
    72→    PROMETHEUS_BASE_URL = 'http://localhost:9090/api/v1/query',
    73→    KAFKA_BROKERS = 'localhost:9092',
    74→    ALERT_TOPIC = 'agorapulse.monitoring.alerts',
    75→    POLL_INTERVAL_MS = '10000',
    76→    MAX_BACKOFF_MS = '60000',
    77→    METRICS_CONFIG_JSON = '{}', // JSON string mapping metricName -> { threshold, type }
    78→    PRODUCER_CLIENT_ID = 'agorapulse-metric-monitor'
    79→} = process.env;
    80→
    81→// Parsed config
    82→let MONITORED_METRICS;
    83→try {
    84→    MONITORED_METRICS = JSON.parse(METRICS_CONFIG_JSON);
    85→} catch (err) {
    86→    console.error('Invalid METRICS_CONFIG_JSON; falling back to defaults.', err);
    87→    MONITORED_METRICS = {
    88→        'model_latency_seconds_p95': {
    89→            threshold: 1.5,
    90→            comparator: 'gt', // greater-than
    91→            severity: 'critical'
    92→        },
    93→        'model_error_rate': {
    94→            threshold: 0.03,
    95→            comparator: 'gt',
    96→            severity: 'warning'
    97→        }
    98→    };
    99→}
   100→
   101→//////////////////////////////
   102→// Utility Helpers
   103→//////////////////////////////
   104→
   105→/**
   106→ * Comparator map translating textual comparator to actual function
   107→ */
   108→const comparatorFn = {
   109→    gt: (value, threshold) => value > threshold,
   110→    gte: (value, threshold) => value >= threshold,
   111→    lt: (value, threshold) => value < threshold,
   112→    lte: (value, threshold) => value <= threshold,
   113→    eq: (value, threshold) => value === threshold
   114→};
   115→
   116→/**
   117→ * Calculate next exponential back-off delay.
   118→ */
   119→function computeBackoff(attempt, baseMs = Number(POLL_INTERVAL_MS), maxMs = Number(MAX_BACKOFF_MS)) {
   120→    const delayMs = Math.min(baseMs * 2 ** attempt, maxMs);
   121→    const jitter = Math.random() * (delayMs * 0.2); // ±20 % jitter
   122→    return delayMs + jitter;
   123→}
   124→
   125→/**
   126→ * Returns current ISO date string (UTC) without milliseconds for concise logs.
   127→ */
   128→function now() {
   129→    return new Date().toISOString().replace(/\.\d{3}Z$/, 'Z');
   130→}
