   132→//////////////////////////////
   133→// Prometheus Client
   134→//////////////////////////////
   135→
   136→class PrometheusClient {
   137→    constructor(baseURL) {
   138→        this.http = axios.create({
   139→            baseURL,
   140→            timeout: 5000
   141→        });
   142→    }
   143→
   144→    /**
   145→     * Query a single PromQL expression
   146→     * @param {string} query
   147→     * @return {Observable<number>} emits single numeric value
   148→     */
   149→    query$(query) {
   150→        return defer(() =>
   151→            from(
   152→                this.http.get('', {
   153→                    params: { query }
   154→                })
   155→            )
   156→        ).pipe(
   157→            map((response) => {
   158→                if (response.data.status !== 'success') {
   159→                    throw new Error(`Prometheus error status: ${response.data.status}`);
   160→                }
   161→                const result = response.data.data.result;
   162→                if (!Array.isArray(result) || result.length === 0) {
   163→                    throw new Error(`No data for query ${query}`);
   164→                }
   165→                // Support both instant vector and scalar responses; take first
   166→                const valuePair = result[0].value; // [ <timestamp>, "<value>" ]
   167→                if (!valuePair || valuePair.length < 2) {
   168→                    throw new Error(`Malformed Prometheus response for ${query}`);
   169→                }
   170→                const numericValue = parseFloat(valuePair[1]);
   171→                if (Number.isNaN(numericValue)) {
   172→                    throw new Error(`Non-numeric Prometheus value for ${query}: ${valuePair[1]}`);
   173→                }
   174→                return numericValue;
   175→            })
   176→        );
   177→    }
   178→}
   179→
   180→//////////////////////////////
   181→// Kafka Producer Singleton
   182→//////////////////////////////
   183→
   184→class KafkaProducer {
   185→    constructor(brokers, clientId) {
   186→        const kafka = new Kafka({
   187→            clientId,
   188→            brokers: brokers.split(','),
   189→            logLevel: logLevel.ERROR // suppress noise, use our own logging
   190→        });
   191→        this.producer = kafka.producer({ allowAutoTopicCreation: true });
   192→        this.connected$ = from(this.producer.connect()).pipe(shareReplay(1));
   193→    }
   194→
   195→    /**
   196→     * Publishes a JSON message to a topic. Handles async connect.
   197→     * @param {string} topic
   198→     * @param {object} payload
   199→     * @returns {Observable<void>}
   200→     */
   201→    send$(topic, payload) {
   202→        return this.connected$.pipe(
   203→            switchMap(() =>
   204→                from(
   205→                    this.producer.send({
   206→                        topic,
   207→                        messages: [
   208→                            {
   209→                                key: payload.metricName,
   210→                                value: JSON.stringify(payload),
   211→                                timestamp: Date.now().toString()
   212→                            }
   213→                        ]
   214→                    })
   215→                )
   216→            ),
   217→            map(() => void 0) // hide Kafka response
   218→        );
   219→    }
   220→
   221→    async shutdown() {
   222→        try {
   223→            await this.producer.disconnect();
   224→            console.info(`[${now()}] Kafka producer disconnected.`);
   225→        } catch (err) {
   226→            console.error('[KafkaProducer] Error during disconnect', err);
   227→        }
   228→    }
   229→}
   230→
   231→//////////////////////////////
   232→// Schema Validation (Ajv)
   233→//////////////////////////////
   234→
   235→const ajv = new Ajv({ allErrors: true, removeAdditional: 'all' });
   236→addFormats(ajv);
   237→
   238→const alertSchema = {
   239→    $id: 'agorapulse.alert',
   240→    type: 'object',
   241→    additionalProperties: false,
   242→    required: [
   243→        'metricName',
   244→        'currentValue',
   245→        'threshold',
   246→        'comparator',
   247→        'severity',
   248→        'timestamp'
   249→    ],
   250→    properties: {
   251→        metricName: { type: 'string', minLength: 1 },
   252→        currentValue: { type: 'number' },
   253→        threshold: { type: 'number' },
   254→        comparator: { enum: ['gt', 'gte', 'lt', 'lte', 'eq'] },
   255→        severity: { enum: ['info', 'warning', 'critical'] },
   256→        timestamp: { type: 'string', format: 'date-time' }
   257→    }
   258→};
   259→
   260→const validateAlert = ajv.compile(alertSchema);
   261→
   262→//////////////////////////////
   263→// MetricMonitor
   264→//////////////////////////////
   265→
   266→class MetricMonitor {
   267→    constructor({
   268→        prometheusClient,
   269→        kafkaProducer,
   270→        metricsConfig,
   271→        pollIntervalMs = 10000
   272→    }) {
   273→        this.prometheus = prometheusClient;
   274→        this.kafka = kafkaProducer;
   275→        this.metricsConfig = metricsConfig;
   276→        this.pollIntervalMs = pollIntervalMs;
   277→        this.stop$ = new Subject(); // graceful stop signal
   278→    }
   279→
   280→    /**
   281→     * Start monitoring loop.
   282→     */
   283→    start() {
   284→        const metricEntries = Object.entries(this.metricsConfig);
   285→
   286→        if (metricEntries.length === 0) {
   287→            console.warn(`[${now()}] No metrics configured for monitoring.`);
   288→            return;
   289→        }
   290→
   291→        console.info(
   292→            `[${now()}] Starting MetricMonitor for ${metricEntries.length} metric(s)…`
   293→        );
   294→
   295→        this.subscription = timer(0, this.pollIntervalMs)
   296→            .pipe(
   297→                takeUntil(this.stop$),
   298→                // For each tick, query metrics in parallel
   299→                switchMap(() =>
   300→                    from(metricEntries).pipe(
   301→                        switchMap(([metricName, cfg]) =>
   302→                            this.checkMetric$(metricName, cfg)
   303→                        )
   304→                    )
   305→                ),
   306→                catchError((err) => {
   307→                    console.error(`[MetricMonitor] Unhandled error`, err);
   308→                    return EMPTY; // swallow; monitoring continues
   309→                })
   310→            )
   311→            .subscribe();
   312→    }
   313→
   314→    /**
   315→     * Stop monitoring loop gracefully.
   316→     */
   317→    stop() {
   318→        this.stop$.next();
   319→        this.stop$.complete();
   320→        this.subscription?.unsubscribe();
   321→    }
   322→
   323→    /**
   324→     * Check a particular metric for anomaly and emit Kafka event when breached.
   325→     * @param {string} metricName
   326→     * @param {object} cfg
   327→     * @returns {Observable<void>}
   328→     */
   329→    checkMetric$(metricName, cfg) {
   330→        const { threshold, comparator = 'gt', severity = 'info', promQuery } = cfg;
   331→
   332→        const query = promQuery || metricName; // use custom query or metric name directly
   333→
   334→        return this.prometheus.query$(query).pipe(
   335→            // Retry with exponential back-off on network/Prometheus errors
   336→            retryWhen((errors) =>
   337→                errors.pipe(
   338→                    scan((acc, err) => {
   339→                        console.warn(
   340→                            `[${now()}] Prometheus query failed (${query}): ${err.message}`
   341→                        );
   342→                        return acc + 1;
   343→                    }, 0),
   344→                    delay((attempt) => computeBackoff(attempt))
   345→                )
   346→            ),
   347→            filter((value) => {
   348→                const compFn = comparatorFn[comparator];
   349→                if (!compFn) {
   350→                    console.error(
   351→                        `[MetricMonitor] Unknown comparator "${comparator}" for metric ${metricName}`
   352→                    );
   353→                    return false;
   354→                }
   355→                return compFn(value, threshold);
   356→            }),
   357→            throttleTime(60000), // de-bounce: emit at most once per minute per metric
   358→            map((value) => {
   359→                const payload = {
   360→                    metricName,
   361→                    currentValue: value,
   362→                    threshold,
   363→                    comparator,
   364→                    severity,
   365→                    timestamp: new Date().toISOString()
   366→                };
   367→                if (!validateAlert(payload)) {
   368→                    console.error(
   369→                        `[MetricMonitor] Invalid alert payload for ${metricName}`,
   370→                        validateAlert.errors
   371→                    );
   372→                    return null;
   373→                }
   374→                return payload;
   375→            }),
   376→            filter(Boolean),
   377→            switchMap((payload) =>
   378→                this.kafka
   379→                    .send$(ALERT_TOPIC, payload)
   380→                    .pipe(
   381→                        tap(() =>
   382→                            console.info(
   383→                                `[${now()}] Anomaly emitted: ${payload.metricName}=${payload.currentValue} (threshold ${payload.comparator} ${payload.threshold})`
   384→                            )
   385→                        )
   386→                    )
   387→            ),
   388→            catchError((err) => {
   389→                console.error(
   390→                    `[MetricMonitor] Error while processing metric ${metricName}`,
   391→                    err
   392→                );
